-- Import all ForeUp courses from platform-wide discovery.
-- 1,789 courses across all US states + Canada.
-- platform_course_id = ForeUp course_id
-- platform_schedule_id = ForeUp schedule_id (teesheet_id)
-- platform_booking_class = ForeUp booking_class_id (public/default)

ON CONFLICT (platform, platform_course_id) DO UPDATE SET
  name = EXCLUDED.name,
  platform_schedule_id = EXCLUDED.platform_schedule_id,
  platform_booking_class = EXCLUDED.platform_booking_class,
  location_city = EXCLUDED.location_city,
  location_state = EXCLUDED.location_state,
  timezone = EXCLUDED.timezone;